  (26, 'dakota-poker-tour-2022-23-eagle-eye', 'Eagle Eye', 'The Eagle Eye Poker Tournament is back with the Dakota Poker Tour! Join us for this SUNDAY 1-day Poker Tournament.', '2023-04-02', '2023-04-02', 6, 'https://dakotapokertour.com/storage/event/medium/DPT-Eagle-Eye-Valley-City-FB-Event-r1-2iVWFMDq.jpg', '/media/dpt/event/DPT-Eagle-Eye-Valley-City-FB-Event-r1-2iVWFMDq.jpg', '{"id":26,"name":"Eagle Eye","alias":"dakota-poker-tour-2022-23-eagle-eye","description":"The Eagle Eye Poker Tournament is back with the Dakota Poker Tour! Join us for this SUNDAY 1-day Poker Tournament.","startDate":"2023-04-02 00:00:00","endDate":"2023-04-02 00:00:00","logo":"DPT-Eagle-Eye-Valley-City-FB-Event-r1-2iVWFMDq.jpg","bannerImage":null,"imageUrl":"https://dakotapokertour.com/storage/event/medium/DPT-Eagle-Eye-Valley-City-FB-Event-r1-2iVWFMDq.jpg","bannerUrl":"","venue":{"id":6,"name":"Valley City Eagles","alias":"valley-city-eagles","city":"Valley City","state":"ND"}}'::jsonb),
