  (387, 'operation-red-white-bluff-final-table', '🏆 Operation Red White & Bluff — Final Table!', 'Congratulations to the Final Table at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff has been an incredible event, and we’re down to the final table! Congratulations to the players who battled through a 58-player field to earn th…', '2025-11-15 20:25:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3978-7AtznfoY.jpg', '/media/dpt/article/IMG_3978-7AtznfoY.jpg', null, '{"id":387,"title":"🏆 Operation Red White & Bluff — Final Table!","alias":"operation-red-white-bluff-final-table","excerpt":"Congratulations to the Final Table at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff has been an incredible event, and we’re down to the final table! Congratulations to the players who battled through a 58-player field to earn th…","publishedAt":"2025-11-15 20:25:00","featured":false,"logo":"IMG_3978-7AtznfoY.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3978-7AtznfoY.jpg","bannerUrl":"","tournament":{"id":330,"name":"Operation Red White & Bluff","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025"}}'::jsonb),
  (386, 'kim-rasmussen-your-chip-leader-as-registration-closes', 'Kim Rasmussen, Your Chip leader  as Registration Closes', 'Registration is officially closed tonight at the Casselton Vets Club! 🇺🇸♠️ We had an awesome turnout with 58 players, building a $13,400 prize pool! Tonight’s winner will be taking home a $4,000 cash payout. 💰🔥 Your chip leader after the di…', '2025-11-15 17:45:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3973-5TekJ52d.jpg', '/media/dpt/article/IMG_3973-5TekJ52d.jpg', null, '{"id":386,"title":"Kim Rasmussen, Your Chip leader  as Registration Closes","alias":"kim-rasmussen-your-chip-leader-as-registration-closes","excerpt":"Registration is officially closed tonight at the Casselton Vets Club! 🇺🇸♠️ We had an awesome turnout with 58 players, building a $13,400 prize pool! Tonight’s winner will be taking home a $4,000 cash payout. 💰🔥 Your chip leader after the di…","publishedAt":"2025-11-15 17:45:00","featured":false,"logo":"IMG_3973-5TekJ52d.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3973-5TekJ52d.jpg","bannerUrl":"","tournament":{"id":330,"name":"Operation Red White & Bluff","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025"}}'::jsonb),
  (385, 'operation-red-white-bluff-today', '🇺🇸 OPERATION RED WHITE & BLUFF – TODAY!', 'Cards are in the air at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff is underway as we honor our veterans today. We’ve already got six tables going strong, and there’s plenty of room for more players. Come out, play some poker,…', '2025-11-15 12:57:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3938-gaMq9iwa.jpg', '/media/dpt/article/IMG_3938-gaMq9iwa.jpg', null, '{"id":385,"title":"🇺🇸 OPERATION RED WHITE & BLUFF – TODAY!","alias":"operation-red-white-bluff-today","excerpt":"Cards are in the air at the Casselton Vets Club! 🇺🇸♠️ Operation Red White & Bluff is underway as we honor our veterans today. We’ve already got six tables going strong, and there’s plenty of room for more players. Come out, play some poker,…","publishedAt":"2025-11-15 12:57:00","featured":false,"logo":"IMG_3938-gaMq9iwa.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3938-gaMq9iwa.jpg","bannerUrl":"","tournament":{"id":330,"name":"Operation Red White & Bluff","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-operation-red-white-bluff-11-15-2025"}}'::jsonb),
