  (383, 'big-night-in-casselton-8-400-prize-pool', 'Big Night in Casselton: $8,400 Prize Pool!', 'Registration is now closed for tonight’s Friday Night Turbo at the Casselton Vets Club! We drew a strong field of 47 players, building an impressive $8,400 prize pool. Tonight’s champion will walk away with $2,500 — not bad for a Friday nig…', '2025-11-14 22:08:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3932-3f4CTESp.jpg', '/media/dpt/article/IMG_3932-3f4CTESp.jpg', null, '{"id":383,"title":"Big Night in Casselton: $8,400 Prize Pool!","alias":"big-night-in-casselton-8-400-prize-pool","excerpt":"Registration is now closed for tonight’s Friday Night Turbo at the Casselton Vets Club! We drew a strong field of 47 players, building an impressive $8,400 prize pool. Tonight’s champion will walk away with $2,500 — not bad for a Friday nig…","publishedAt":"2025-11-14 22:08:00","featured":false,"logo":"IMG_3932-3f4CTESp.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3932-3f4CTESp.jpg","bannerUrl":"","tournament":{"id":329,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025"}}'::jsonb),
  (380, 'castleton-vets-club-friday-night-turbo', 'Castleton Vets Club Friday Night Turbo', 'Cards are in the air tonight at the Casselton Vets Club for the Friday Night Turbo! ♠️ We’ve got 5 tables set and room for more — registration is open until 8:15 PM. Come play some poker and support the local Casselton Vets Club! Friday Nig…', '2025-11-14 18:46:00', null, 'dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025', 'https://dakotapokertour.com/storage/article/thumb/IMG_3912-tJdpGWFr.jpg', '/media/dpt/article/IMG_3912-tJdpGWFr.jpg', null, '{"id":380,"title":"Castleton Vets Club Friday Night Turbo","alias":"castleton-vets-club-friday-night-turbo","excerpt":"Cards are in the air tonight at the Casselton Vets Club for the Friday Night Turbo! ♠️ We’ve got 5 tables set and room for more — registration is open until 8:15 PM. Come play some poker and support the local Casselton Vets Club! Friday Nig…","publishedAt":"2025-11-14 18:46:00","featured":false,"logo":"IMG_3912-tJdpGWFr.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/IMG_3912-tJdpGWFr.jpg","bannerUrl":"","tournament":{"id":329,"name":"Friday Night Turbo","alias":"dakota-poker-tour-2025-operation-poker-red-white-bluff-honoring-heroes-for-veteran-s-day-at-the-casselton-vets-friday-night-turbo-11-14-2025"}}'::jsonb),
