  (377, 'cards-are-in-the-air-for-the-l-i-s-t-e-n-inc-monster-stack', '♠️ Cards are in the air for the L.I.S.T.E.N. INC. MONSTER STACK! ♠️', 'We have 6 tables going strong and growing! With plenty of room to jump in! Get down here and join the action! 💰 $300 Buy-In | Freezeout Format 💵 100K Starting Stack ⏱️ 30-Min Levels 🕕 Late Registration Open Until 6PM One shot. One stack. On…', '2025-11-01 11:50:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025', 'https://dakotapokertour.com/storage/article/thumb/playmakers2-c3Z8EGTy.jpg', '/media/dpt/article/playmakers2-c3Z8EGTy.jpg', null, '{"id":377,"title":"♠️ Cards are in the air for the L.I.S.T.E.N. INC. MONSTER STACK! ♠️","alias":"cards-are-in-the-air-for-the-l-i-s-t-e-n-inc-monster-stack","excerpt":"We have 6 tables going strong and growing! With plenty of room to jump in! Get down here and join the action! 💰 $300 Buy-In | Freezeout Format 💵 100K Starting Stack ⏱️ 30-Min Levels 🕕 Late Registration Open Until 6PM One shot. One stack. On…","publishedAt":"2025-11-01 11:50:00","featured":false,"logo":"playmakers2-c3Z8EGTy.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/playmakers2-c3Z8EGTy.jpg","bannerUrl":"","tournament":{"id":328,"name":"LISTEN INC MONSTER STACK","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025"}}'::jsonb),
  (376, 'get-ready-for-the-l-i-s-t-e-n-inc-monster-stack', '🔥 Get Ready for the L.I.S.T.E.N. INC. MONSTER STACK! 🔥', 'It’s one of the biggest events of the season – and it’s happening **TODAY!!** A full day of deep stacks, big blinds, and serious poker action awaits. 🗓️ Saturday, November 1, 2025 🕚 New Start Time: 11AM 💰 $300 Buy-In | One-Day Monster Stack…', '2025-11-01 11:00:00', null, 'dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025', 'https://dakotapokertour.com/storage/article/thumb/dpt2-EexLyMqt.jpg', '/media/dpt/article/dpt2-EexLyMqt.jpg', null, '{"id":376,"title":"🔥 Get Ready for the L.I.S.T.E.N. INC. MONSTER STACK! 🔥","alias":"get-ready-for-the-l-i-s-t-e-n-inc-monster-stack","excerpt":"It’s one of the biggest events of the season – and it’s happening **TODAY!!** A full day of deep stacks, big blinds, and serious poker action awaits. 🗓️ Saturday, November 1, 2025 🕚 New Start Time: 11AM 💰 $300 Buy-In | One-Day Monster Stack…","publishedAt":"2025-11-01 11:00:00","featured":false,"logo":"dpt2-EexLyMqt.jpg","banner":null,"videoUrl":null,"imageUrl":"https://dakotapokertour.com/storage/article/thumb/dpt2-EexLyMqt.jpg","bannerUrl":"","tournament":{"id":328,"name":"LISTEN INC MONSTER STACK","alias":"dakota-poker-tour-2025-l-i-s-t-e-n-inc-listen-inc-monster-stack-11-01-2025"}}'::jsonb),
